\displaystyle{\begin{aligned}
   {\frac{\frac{2y}{y^{2}-9}+5}{\frac{2}{y+3}-\frac{5}{y-3}}}
      \amp = {\frac{\frac{2y}{\left(y+3\right)\mathopen{}\left(y-3\right)}+5}{\frac{2}{y+3}-\frac{5}{y-3}}} \\
      \amp = {\frac{\frac{2y}{\left(y+3\right)\mathopen{}\left(y-3\right)}+5}{\frac{2}{y+3}-\frac{5}{y-3}}} \cdot \frac{{\left(y+3\right)\mathopen{}\left(y-3\right)}}{{\left(y+3\right)\mathopen{}\left(y-3\right)}} \\
      \amp = {\frac{\frac{2y}{\left(y+3\right)\mathopen{}\left(y-3\right)}\mathopen{}\left(y+3\right)\mathopen{}\left(y-3\right)+5\mathopen{}\left(y+3\right)\mathopen{}\left(y-3\right)}{\frac{2}{y+3}\mathopen{}\left(y+3\right)\mathopen{}\left(y-3\right)-\frac{5}{y-3}\mathopen{}\left(y+3\right)\mathopen{}\left(y-3\right)}} \\
      \amp = {\frac{2y+5\mathopen{}\left(y^{2}-9\right)}{2\mathopen{}\left(y-3\right)-5\mathopen{}\left(y+3\right)}}, y \ne 3 \text{ and } y \ne -3 \\
      \amp = {\frac{2y+5y^{2}-45}{2y-6-5y-15}}, y \ne 3 \text{ and } y \ne -3 \\
      \amp = {\frac{5y^{2}+2y-45}{3\mathopen{}\left(-y-7\right)}, y\ne -3\hbox{ and }y\ne 3}
